  defaultControls,
  gamepadButtonLabels,
  initialTuning,
  judgementCssVars,
  laneColor,
  lanes,
  makeBeatmapAttack,
  normalizeBeatmap,
  readStoredNumber,
  timelineLaneAreaHeightPx,
  timelineLaneTopPx,
  type Attack,
  type Beatmap,
  type BeatmapNote,
